var DLG = {"tina": [{"when": "ch1==2", "cmd": "quest", "label": "委託", "name": "緹娜", "lines": ["委託完成確認——哥布林頭目討伐！", "報酬 200 金幣已支付。你們是本鎮的驕傲！", "（第一章完──「重返礦山」即將開放）"], "action": "ch1_reward"}, {"when": "ch1==1", "cmd": "quest", "label": "委託", "name": "緹娜", "lines": ["委託進行中：討伐東之森深處的哥布林頭目。", "牠就在森林最東邊的空地，小心點！"]}, {"when": "reg==1", "cmd": "quest", "label": "委託", "name": "緹娜", "lines": ["有新委託喔——農家回報東之森的哥布林越來越囂張，", "牠們的頭目就盤踞在森林深處。", "【委託】討伐哥布林頭目（報酬 200G）。接受嗎？就當你接受了！", "頭目比雜魚強得多——建議練到 Lv5、跟漢克拿把好劍再去。"], "action": "ch1_take"}, {"when": "step>=3", "cmd": "quest", "label": "委託", "name": "緹娜", "lines": ["歡迎來到冒險者公會！要登錄成為冒險者嗎？", "……路德和瑪琳，兩位都登錄完成！", "從今天起你們就是 F 級冒險者了。委託隨時來找我。"], "action": "register"}, {"when": "always", "cmd": "quest", "label": "委託", "name": "緹娜", "lines": ["目前沒有適合你們的新委託。", "升上一階、或到週邊多探探，說不定就有新工作囉。"]}, {"when": "step==0", "cmd": "talk", "name": "緹娜", "lines": ["這不是路德嗎？要去礦山見習？", "等你正式登錄的那天，公會隨時歡迎你。"]}, {"when": "ch1==3", "cmd": "talk", "name": "緹娜", "lines": ["哥布林頭目的委託已經結案囉，辛苦了！", "接下來想找活兒的話，水井旁的老葛雷正在找人幫忙。"]}, {"when": "ch2>=1", "cmd": "talk", "name": "緹娜", "lines": ["礦坑的委託，是老葛雷私下拜託你們的吧？", "那些失蹤的礦工……公會這邊也一直很掛心。", "小心點，別逞強——活著回來才是好冒險者。"]}, {"when": "always", "cmd": "talk", "name": "緹娜", "lines": ["委託都貼在牆上的告示板，慢慢看。", "有什麼想問的，儘管來櫃檯找我。"]}], "dora": [{"when": "always", "cmd": "rest", "label": "住宿", "name": "朵拉", "lines": ["累了吧？床鋪都幫你們鋪好了。", "（隊伍完全恢復了！）"], "action": "heal"}, {"when": "step==0", "cmd": "talk", "name": "朵拉", "lines": ["要跟亞倫先生出門？路上小心。", "回來我煮好吃的等你們。"]}, {"when": "always", "cmd": "talk", "name": "朵拉", "lines": ["瑪琳那孩子，就拜託你多照應了。", "想歇歇隨時說一聲，自己家不收錢的。"]}], "sister": [{"when": "ch2>=2", "cmd": "pray", "label": "祈禱", "name": "希雅修女", "lines": ["你們從礦山帶回來的……不只是疲憊。", "那是亡者未能安息的哀嘆。願蓋婭女神接引他們。", "（隊伍完全恢復了！）", "……路德，女神在你身上的記號，又亮了一分。"], "action": "heal"}, {"when": "always", "cmd": "pray", "label": "祈禱", "name": "希雅修女", "lines": ["願蓋婭女神看顧你們的旅途。", "（在女神像前禱告，隊伍完全恢復了！）"], "action": "heal"}, {"when": "step==0", "cmd": "talk", "name": "希雅修女", "lines": ["蓋婭女神看顧著每一位旅人。"]}, {"when": "always", "cmd": "talk", "name": "希雅修女", "lines": ["……女神在你身上留了記號呢。願風平息。", "累了就來祈禱，女神的恩澤不分你我。"]}], "barton": [{"when": "ch2>=3", "cmd": "talk", "name": "巴頓鎮長", "lines": ["礦工失蹤的事……我早該多過問一句的。", "孩子，你們比這鎮上所有大人都勇敢。", "把礦山看到的一切，原原本本告訴大城的人吧。"]}, {"when": "ch1==3", "cmd": "talk", "name": "巴頓鎮長", "lines": ["哥布林的事多虧你們了。", "但礦山的異變……我總覺得沒那麼簡單。"]}, {"when": "step==0", "cmd": "talk", "name": "巴頓鎮長", "lines": ["聽說亞倫先生要帶你去礦山見習？", "好好跟著學，別亂跑。"]}, {"when": "always", "cmd": "talk", "name": "巴頓鎮長", "lines": ["礦山最近不太平靜，連老獵人都不敢靠近。", "亞倫先生的事……我很遺憾。孩子，別勉強自己。"]}], "hank": [{"when": "ch1>=1", "done": "gotSword", "cmd": "hank_gift", "label": "臨別贈言", "name": "漢克", "lines": ["……路德，你也要出去闖了啊。", "拿去，我打的劍。別死在外面。", "（獲得『鐵劍』！開啟 選單→裝備 分頁換上它）"], "action": "give_sword"}, {"when": "reg==1", "cmd": "trade", "label": "交易", "name": "漢克", "lines": ["冒險者？裝備可不能馬虎。來，看看我的貨。"], "action": "shop_hank"}, {"when": "always", "cmd": "trade", "label": "交易", "name": "漢克", "lines": ["要補貨就直說，鐵匠鋪隨時開著。"], "action": "shop_hank"}, {"when": "step==0", "cmd": "talk", "name": "漢克", "lines": ["哼，礦山？", "……跟緊亞倫先生，別給他添麻煩。"]}, {"when": "always", "cmd": "talk", "name": "漢克", "lines": ["冒險者？哼，那不是鬧著玩的。", "你亞倫大哥那麼強的人都……算了。要去就去吧。"]}], "martha": [{"when": "always", "done": "gotRing", "cmd": "martha_gift", "label": "母親的心意", "name": "瑪莎", "lines": ["你這孩子，越來越像年輕時的你爸了。", "這枚戒指你戴著——是我年輕時你爸打的，保平安。", "（獲得『活力戒指』！開啟 選單→裝備 可以裝上）"], "action": "give_ring"}, {"when": "always", "cmd": "talk", "name": "瑪莎", "lines": ["你這孩子，越來越像年輕時的你爸了。", "路上一定要吃飽穿暖，聽到沒？"]}], "gid": [{"when": "always", "done": "gotPotion", "cmd": "gid_gift", "label": "新客招待", "name": "吉德", "lines": ["第一次上門吧？來，先送你 2 瓶藥水，別客氣。", "補給要趁早，這是老冒險者的鐵則！", "（獲得『藥水』×2！）"], "action": "give_potion"}, {"when": "always", "cmd": "trade", "label": "交易", "name": "吉德", "lines": ["歡迎光臨！要看看我店裡的商品嗎？"], "action": "shop_gid"}, {"when": "always", "cmd": "talk", "name": "吉德", "lines": ["藥水備齊再出門，這是老冒險者的鐵則！", "缺什麼儘管開口，我這什麼都有。"]}], "gray": [{"when": "relic==1", "name": "老葛雷", "lines": ["這頂頭盔……是阿吉的！你們在裡頭找到的？", "（老葛雷的手抖個不停