always", "cmd": "talk", "name": "希雅修女", "lines": ["……女神在你身上留了記號呢。願風平息。", "累了就來祈禱，女神的恩澤不分你我。"]}], "barton": [{"when": "ch2>=3", "cmd": "talk", "name": "巴頓鎮長", "lines": ["礦工失蹤的事……我早該多過問一句的。", "孩子，你們比這鎮上所有大人都勇敢。", "把礦山看到的一切，原原本本告訴大城的人吧。"]}, {"when": "ch1==3", "cmd": "talk", "name": "巴頓鎮長", "lines": ["哥布林的事多虧你們了。", "但礦山的異變……我總覺得沒那麼簡單。"]}, {"when": "step==0", "cmd": "talk", "name": "巴頓鎮長", "lines": ["聽說亞倫先生要帶你去礦山見習？", "好好跟著學，別亂跑。"]}, {"when": "always", "cmd": "talk", "name": "巴頓鎮長", "lines": ["礦山最近不太平靜，連老獵人都不敢靠近。", "亞倫先生的事……我很遺憾。孩子，別勉強自己。"]}], "hank": [{"when": "ch1>=1", "done": "gotSword", "cmd": "hank_gift", "label": "臨別贈言", "name": "漢克", "lines": ["……路德，你也要出去闖了啊。", "拿去，我打的劍。別死在外面。", "（獲得『鐵劍』！開啟 選單→裝備 分頁換上它）"], "action": "give_sword"}, {"when": "reg==1", "cmd": "trade", "label": "交易", "name": "漢克", "lines": ["冒險者？裝備可不能馬虎。來，看看我的貨。"], "action": "shop_hank"}, {"when": "always", "cmd": "trade", "label": "交易", "name": "漢克", "lines": ["要補貨就直說，鐵匠鋪隨時開著。"], "action": "shop_hank"}, {"when": "step==0", "cmd": "talk", "name": "漢克", "lines": ["哼，礦山？", "……跟緊亞倫先生，別給他添麻煩。"]}, {"when": "always", "cmd": "talk", "name": "漢克", "lines": ["冒險者？哼，那不是鬧著玩的。", "你亞倫大哥那麼強的人都……算了。要去就去吧。"]}], "martha": [{"when": "always", "done": "gotRing", "cmd": "martha_gift", "label": "母親的心意", "name": "瑪莎", "lines": ["你這孩子，越來越像年輕時的你爸了。", "這枚戒指你戴著——是我年輕時你爸打的，保平安。", "（獲得『活力戒指』！開啟 選單→裝備 可以裝上）"], "action": "give_ring"}, {"when": "always", "cmd": "talk", "name": "瑪莎", "lines": ["你這孩子，越來越像年輕時的你爸了。", "路上一定要吃飽穿暖，聽到沒？"]}], "gid": [{"when": "always", "done": "gotPotion", "cmd": "gid_gift", "label": "新客招待", "name": "吉德", "lines": ["第一次上門吧？來，先送你 2 瓶藥水，別客氣。", "補給要趁早，這是老冒險者的鐵則！", "（獲得『藥水』×2！）"], "action": "give_potion"}, {"when": "always", "cmd": "trade", "label": "交易", "name": "吉德", "lines": ["歡迎光臨！要看看我店裡的商品嗎？"], "action": "shop_gid"}, {"when": "always", "cmd": "talk", "name": "吉德", "lines": ["藥水備齊再出門，這是老冒險者的鐵則！", "缺什麼儘管開口，我這什麼都有。"]}], "gray": [{"when": "relic==1", "name": "老葛雷", "lines": ["這頂頭盔……是阿吉的！你們在裡頭找到的？", "（老葛雷的手抖個不停